import styled from "styled-components"
import { Link } from "gatsby"
import v from "../../data/variables"

export const FileList = styled.div`
  border-top: 1px solid ${v.line};
`

export const FileRow = styled(Link)`
  position: relative;
  display: grid;
  grid-template-columns: minmax(0, 5fr) minmax(0, 7fr);
  gap: clamp(1.75rem, 4vw, 4rem);
  align-items: center;
  padding: clamp(2.25rem, 6vh, 4rem) 0;
  border-bottom: 1px solid ${v.line};
  color: inherit;

  .meta {
    display: flex;
    flex-wrap: wrap;
    gap: 0.6em 1.5em;
    font-family: ${v.fontMono};
    font-size: var(--text-mono-s);
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: ${v.faint};

    .code {
      color: ${v.signal};
      font-weight: 600;
    }
  }

  .title {
    display: flex;
    align-items: baseline;
    gap: 0.55em;
    margin-top: 1.1rem;
    font-family: ${v.fontDisplay};
    font-weight: normal;
    font-size: clamp(1.9rem, 4vw, 3.4rem);
    line-height: 0.98;
    text-transform: uppercase;
    color: ${v.text};
    transition: color 0.25s ease;

    .arrow {
      flex: none;
      font-family: ${v.fontMono};
      font-size: 0.5em;
      color: ${v.signal};
      opacity: 0;
      transform: translateX(-8px);
      transition: opacity 0.3s var(--ease-out), transform 0.3s var(--ease-out);
    }
  }

  .desc {
    margin-top: 1.2rem;
    max-width: 52ch;
    font-size: 1rem;
    line-height: 1.8;
    color: ${v.dim};
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .chips {
    margin-top: 1.4rem;
  }

  .media {
    position: relative;
    overflow: hidden;
    border: 1px solid ${v.lineFaint};
    background: ${v.panel};

    .gatsby-image-wrapper {
      filter: grayscale(1) contrast(1.08) brightness(0.95);
      transform: scale(1.01);
      transition: filter 0.5s ease, transform 1.2s var(--ease-out);
    }

    /* crimson-multiply duotone that lifts on hover */
    &::after {
      content: "";
      position: absolute;
      inset: 0;
      z-index: 1;
      background: ${v.crimson};
      mix-blend-mode: multiply;
      opacity: 1;
      transition: opacity 0.45s ease;
      pointer-events: none;
    }

    &::before {
      content: "";
      position: absolute;
      left: 0;
      right: 0;
      top: 0;
      height: 32%;
      z-index: 2;
      transform: translateY(-102%);
      background: linear-gradient(
        to bottom,
        rgba(225, 49, 72, 0),
        rgba(225, 49, 72, 0.16) 45%,
        rgba(225, 49, 72, 0.38) 50%,
        rgba(225, 49, 72, 0) 100%
      );
      pointer-events: none;
    }
  }

  &:hover,
  &:focus-visible {
    .title {
      color: ${v.signal};
    }
    .arrow {
      opacity: 1;
      transform: translateX(0);
    }
    .media::after {
      opacity: 0;
    }
    .media::before {
      animation: scanSweep 0.85s ease-out 1;
    }
    .media .gatsby-image-wrapper {
      filter: none;
      transform: scale(1.04);
    }
  }

  @media (max-width: ${v.breakpointPhone}) {
    grid-template-columns: 1fr;
    gap: 1.25rem;

    .media {
      order: 2;
    }
  }
`
